@code {
    [Parameter] public Models.NotificationPrefs? Prefs { get; set; }
    [Parameter] public List<string> AllChannels { get; set; } = [];
    [Parameter] public EventCallback<Models.NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications { get; set; }
    private bool PushNotifications { get; set; }
    private bool WeeklyDigest { get; set; }
    private List<string> MutedChannels { get; set; } = [];
    private bool _saved;

    protected override void OnParametersSet()
    {
        if (Prefs is null) return;
        EmailNotifications = Prefs.EmailNotifications;
        PushNotifications = Prefs.PushNotifications;
        WeeklyDigest = Prefs.WeeklyDigest;
        MutedChannels = [.. Prefs.MutedChannels];
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task Save()
    {
        var updated = new Models.NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
        await OnSave.InvokeAsync(updated);
        _saved = true;
    }
}

@namespace sv_db616d1790554852b52ae3908d2e1e9e.Components.Pages.Settings

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor: pointer;" @onclick="() => _expanded = !_expanded">
        <span>🔑 Change Password</span>
        <span>@(_expanded ? "▲" : "▼")</span>
    </div>
    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="alert alert-danger py-2">@_error</div>
            }
            @if (_success)
            {
                <div class="alert alert-success py-2">Password updated successfully!</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@_updating">
                @(_updating ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _error;
    private bool _success;
    private bool _updating;

    private async Task UpdatePassword()
    {
        _error = null;
        _success = false;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            _error = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _error = "New password and confirmation do not match.";
            return;
        }

        _updating = true;
        await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
        _updating = false;
        _success = true;
        _currentPassword = _newPassword = _confirmPassword = "";
    }
}

@namespace sv_db616d1790554852b52ae3908d2e1e9e.Components.Pages.Settings

@if (_sessionToRevoke is not null)
{
    <div class="modal-backdrop show"></div>
    <div class="modal d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>
                        Are you sure you want to revoke the session on
                        <strong>@_sessionToRevoke.Device</strong> from
                        <strong>@_sessionToRevoke.Location</strong>?
                    </p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private Models.ActiveSession? _sessionToRevoke;
    private TaskCompletionSource<bool>? _tcs;

    public Task<bool> ShowAsync(Models.ActiveSession session)
    {
        _sessionToRevoke = session;
        _tcs = new TaskCompletionSource<bool>();
        StateHasChanged();
        return _tcs.Task;
    }

    private void Confirm()
    {
        _sessionToRevoke = null;
        _tcs?.SetResult(true);
    }

    private void Cancel()
    {
        _sessionToRevoke = null;
        _tcs?.SetResult(false);
    }
}

@namespace sv_db616d1790554852b52ae3908d2e1e9e.Components.Pages.Settings

<div class="settings-section">
    <h4>Security</h4>
    <hr />

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="form-check form-switch mb-4">
        <input class="form-check-input" type="checkbox" id="twoFactor"
               checked="@TwoFactorEnabled"
               @onchange="e => TwoFactorEnabled = (bool)e.Value!" />
        <label class="form-check-label" for="twoFactor">
            Two-Factor Authentication
            @if (TwoFactorEnabled)
            {
                <span class="badge bg-success ms-2">Enabled</span>
            }
            else
            {
                <span class="badge bg-secondary ms-2">Disabled</span>
            }
        </label>
    </div>

    @if (Security?.LastPasswordChange is not null)
    {
        <p class="text-muted small">
            Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
        </p>
    }

    <h6>Active Sessions</h6>
    <div class="table-responsive">
        <table class="table table-striped table-sm">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @if (Security?.Sessions is not null)
                {
                    @foreach (var session in Security.Sessions)
                    {
                        var isCurrent = session.Id == CurrentSessionId;
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
                                @if (isCurrent)
                                {
                                    <span class="badge bg-info">Current</span>
                                }
                                else
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => RequestRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                }
            </tbody>
        </table>
    </div>

    <RevokeSessionDialog @ref="_revokeDialog" />
</div>

@code {
    [Parameter] public Models.SecuritySettings? Security { get; set; }
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool TwoFactorEnabled { get; set; }
    private RevokeSessionDialog _revokeDialog = default!;

    protected override void OnParametersSet()
    {
        if (Security is not null)
            TwoFactorEnabled = Security.TwoFactorEnabled;
    }

    private async Task RequestRevoke(Models.ActiveSession session)
    {
        var confirmed = await _revokeDialog.ShowAsync(session);
        if (confirmed)
        {
            await OnRevokeSession.InvokeAsync(session.Id);
        }
    }
}

