        <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
    </div>

    <h6 class="mt-4">Muted Channels</h6>
    @foreach (var channel in AllChannels)
    {
        var isMuted = MutedChannels.Contains(channel);
        <div class="form-check mb-2">
            <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                   checked="@isMuted"
                   @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
            <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
        </div>
    }

    <button class="btn btn-primary mt-3" @onclick="Save">Save Preferences</button>

    @if (_saved)
    {
        <div class="alert alert-success mt-3 mb-0">Notification preferences saved!</div>
    }
</div>

@code {
    [Parameter] public Models.NotificationPrefs? Prefs { get; set; }
    [Parameter] public List<string> AllChannels { get; set; } = [];
    [Parameter] public EventCallback<Models.NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications { get; set; }
    private bool PushNotifications { get; set; }
    private bool WeeklyDigest { get; set; }
    private List<string> MutedChannels { get; set; } = [];
    private bool _saved;

    protected override void OnParametersSet()
    {
        if (Prefs is null) return;
        EmailNotifications = Prefs.EmailNotifications;
        PushNotifications = Prefs.PushNotifications;
        WeeklyDigest = Prefs.WeeklyDigest;
        MutedChannels = [.. Prefs.MutedChannels];
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task Save()
    {
        var updated = new Models.NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
        await OnSave.InvokeAsync(updated);
        _saved = true;
    }
}
