<div class="settings-section">
    <h4>Profile</h4>
    <hr />

    <div class="avatar-preview mb-3">
        <img src="@AvatarUrl" alt="Avatar" class="rounded-circle" width="80" height="80" />
        <div class="mt-1 text-muted small text-truncate" style="max-width: 300px;" title="@AvatarUrl">
            @AvatarUrl
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label">Display Name</label>
        <input type="text" class="form-control" @bind="DisplayName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" @bind="Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Bio</label>
        <textarea class="form-control" rows="3" @bind="Bio"></textarea>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="Save">Save Changes</button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>

    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert @_statusCss mt-3 mb-0" role="alert">@_statusMessage</div>
    }
</div>

@code {
    [Parameter] public Models.UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<Models.UserProfile> OnSave { get; set; }

    private string DisplayName { get; set; } = "";
    private string Email { get; set; } = "";
    private string AvatarUrl { get; set; } = "";
    private string Bio { get; set; } = "";

    private string? _statusMessage;
    private string _statusCss = "alert-success";

    protected override void OnParametersSet()
    {
        if (Profile is not null && _statusMessage is null)
        {
            LoadFromProfile();
        }
    }

    private void LoadFromProfile()
    {
        DisplayName = Profile!.DisplayName;
        Email = Profile.Email;
        AvatarUrl = Profile.AvatarUrl;
        Bio = Profile.Bio;
    }

    private async Task Save()
    {
        var updated = new Models.UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        _statusMessage = "Profile saved successfully!";
        _statusCss = "alert-success";
    }

    private void Discard()
    {
        if (Profile is not null) LoadFromProfile();
        _statusMessage = "Changes discarded.";
        _statusCss = "alert-info";
    }
}

