        <input class="form-check-input" type="checkbox" id="twoFactor"
               checked="@TwoFactorEnabled"
               @onchange="e => TwoFactorEnabled = (bool)e.Value!" />
        <label class="form-check-label" for="twoFactor">
            Two-Factor Authentication
            @if (TwoFactorEnabled)
            {
                <span class="badge bg-success ms-2">Enabled</span>
            }
            else
            {
                <span class="badge bg-secondary ms-2">Disabled</span>
            }
        </label>
    </div>

    @if (Security?.LastPasswordChange is not null)
    {
        <p class="text-muted small">
            Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
        </p>
    }

    <h6>Active Sessions</h6>
    <div class="table-responsive">
        <table class="table table-striped table-sm">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @if (Security?.Sessions is not null)
                {
                    @foreach (var session in Security.Sessions)
                    {
                        var isCurrent = session.Id == CurrentSessionId;
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
                                @if (isCurrent)
                                {
                                    <span class="badge bg-info">Current</span>
                                }
                                else
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => RequestRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                }
            </tbody>
        </table>
    </div>

    <RevokeSessionDialog @ref="_revokeDialog" />
</div>

@code {
    [Parameter] public Models.SecuritySettings? Security { get; set; }
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool TwoFactorEnabled { get; set; }
    private RevokeSessionDialog _revokeDialog = default!;

    protected override void OnParametersSet()
    {
        if (Security is not null)
            TwoFactorEnabled = Security.TwoFactorEnabled;
    }

    private async Task RequestRevoke(Models.ActiveSession session)
    {
        var confirmed = await _revokeDialog.ShowAsync(session);
        if (confirmed)
        {
            await OnRevokeSession.InvokeAsync(session.Id);
        }
    }
}

@namespace sv_db616d1790554852b52ae3908d2e1e9e.Components.Pages.Settings

<div class="settings-section">
    <h4>Appearance</h4>
    <hr />

    <div class="mb-4">
        <label class="form-label fw-semibold">Theme</label>
        <div>
            @foreach (var theme in new[] { "Light", "Dark", "System" })
            {
                <div class="form-check form-check-inline">
                    <input class="form-check-input" type="radio" name="theme"
                           id="@($"theme-{theme}")" value="@theme"
                           checked="@(Theme == theme)"
                           @onchange="() => Theme = theme" />
                    <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                </div>
            }
        </div>
    </div>

    <div class="mb-4">
        <label class="form-label fw-semibold">Font Size</label>
        <div>
            @foreach (var size in new[] { "Small", "Medium", "Large" })
            {
                <div class="form-check form-check-inline">
                    <input class="form-check-input" type="radio" name="fontSize"
                           id="@($"fs-{size}")" value="@size"
                           checked="@(FontSize == size)"
                           @onchange="() => FontSize = size" />
                    <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                </div>
            }
        </div>
    </div>

    <div class="mb-4">
        <label class="form-label fw-semibold" for="language">Language</label>
        <select class="form-select" id="language" style="max-width: 250px;"
                @bind="Language">
            <option value="English">English</option>
            <option value="Spanish">Spanish</option>
            <option value="French">French</option>
            <option value="German">German</option>
            <option value="Japanese">Japanese</option>
        </select>
    </div>

    <div class="form-check form-switch mb-4">
        <input class="form-check-input" type="checkbox" id="compactMode"
               checked="@CompactMode"
               @onchange="e => CompactMode = (bool)e.Value!" />
        <label class="form-check-label" for="compactMode">Compact Mode</label>
    </div>

    <h6>Preview</h6>
    <div class="appearance-preview p-3 rounded border mb-3"
         style="@PreviewStyle">
        <p class="mb-1"><strong>Sample Heading</strong></p>
        <p class="mb-1">This is how your content will appear with the selected settings.</p>
        <button class="btn btn-sm btn-primary">Sample Button</button>
    </div>

    <button class="btn btn-primary" @onclick="Save">Save</button>

    @if (_saved)
    {
        <div class="alert alert-success mt-3 mb-0">Appearance settings saved!</div>
    }
</div>

@code {
    [Parameter] public Models.AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<Models.AppearanceSettings> OnSave { get; set; }

    private string Theme { get; set; } = "Light";
    private string FontSize { get; set; } = "Medium";
    private string Language { get; set; } = "English";
    private bool CompactMode { get; set; }
    private bool _saved;

    protected override void OnParametersSet()
    {
        if (Settings is null) return;
        Theme = Settings.Theme;
        FontSize = Settings.FontSize;
        Language = Settings.Language;
        CompactMode = Settings.CompactMode;
    }

    private string PreviewStyle
    {
        get
        {
            var bg = Theme switch { "Dark" => "#1e1e1e", "System" => "#f0f0f0", _ => "#ffffff" };
            var fg = Theme == "Dark" ? "#e0e0e0" : "#212529";
            var fs = FontSize switch { "Small" => "0.85rem", "Large" => "1.15rem", _ => "1rem" };
            var pad = CompactMode ? "0.5rem" : "1rem";
            return $"background-color:{bg}; color:{fg}; font-size:{fs}; padding:{pad};";
        }
    }

    private async Task Save()
    {
        var updated = new Models.AppearanceSettings(Theme, FontSize, Language, CompactMode);
        await OnSave.InvokeAsync(updated);
        _saved = true;
    }
}

