@page "/settings"
@rendermode InteractiveServer

@using sv_db616d1790554852b52ae3908d2e1e9e.Models
@using sv_db616d1790554852b52ae3908d2e1e9e.Services

@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionChanged="s => { _activeSection = s; _statusMessage = null; }" />

    <div class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="@_profile" OnSave="SaveProfile" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@_notifications"
                                          AllChannels="@MockSettingsService.AllChannels"
                                          OnSave="SaveNotifications" />
                    break;
                case "Security":
                    <SecuritySection Security="@_security"
                                     OnChangePassword="ChangePassword"
                                     OnRevokeSession="RevokeSession" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="@_appearance" OnSave="SaveAppearance" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
    private bool _loading = true;
    private string? _statusMessage;

    private UserProfile? _profile;
    private NotificationPrefs? _notifications;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        _notifications = await SettingsService.GetNotificationPrefsAsync();
        _security = await SettingsService.GetSecuritySettingsAsync();
        _appearance = await SettingsService.GetAppearanceAsync();
        _loading = false;
    }

    private async Task SaveProfile(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotifications(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notifications = prefs;
    }

    private async Task ChangePassword((string Current, string New) pw)
    {
        await SettingsService.ChangePasswordAsync(pw.Current, pw.New);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearance(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
    }
}

.settings-dashboard {
    display: flex;
    gap: 2rem;
    min-height: 500px;
}

.settings-sidebar {
    min-width: 200px;
    max-width: 220px;
    border-right: 1px solid #dee2e6;
    padding-right: 1rem;
}

.sidebar-title {
    padding: 0.5rem 0.75rem;
    margin-bottom: 0.25rem;
    font-weight: 600;
    color: #6c757d;
    text-transform: uppercase;
    font-size: 0.75rem;
    letter-spacing: 0.05em;
}

::deep .settings-sidebar .nav-link {
    color: #495057;
    border-radius: 0.375rem;
    padding: 0.5rem 0.75rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    cursor: pointer;
}

::deep .settings-sidebar .nav-link:hover {
    background-color: #f8f9fa;
}

::deep .settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: #fff;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

.settings-section h4 {
    margin-bottom: 0.25rem;
}

::deep .avatar-preview {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
}

::deep .appearance-preview {
    transition: all 0.2s ease;
}

::deep .modal-backdrop {
    z-index: 1040;
}

::deep .modal {
    z-index: 1050;
}

